def build_item(t: tuple) -> dict:
    side, source, title, summary, quote, absurdity, mi, kw = t
    country, host = SRC[source]
    return {
        "side": side,
        "source": source,
        "source_country": country,
        "source_url": url_for(source, kw),
        "topic": None,  # 由调用方按分组填
        "title_cn": title,
        "summary_cn": summary,
        "quote_cn": quote,
        "absurdity": absurdity,
        "published": TODAY,
        "mirror_issue": mi,
    }


# topic -> 该 topic 下 NEW 段的起止（按上面顺序连续排列）
# 用分隔注释定位；这里直接按 topic 顺序映射
TOPIC_ORDER = [
    "政治","经济","社会","科技","军事","外交","文化","环境","电影","娱乐","其他",
]


def assign_topics():
    """把 NEW 列表按 topic 分组（每 30 条一个 topic，15 left + 15 right）。"""
    assert len(NEW) == len(TOPIC_ORDER) * 30, f"NEW 条数 {len(NEW)} != {len(TOPIC_ORDER)*30}"
    by_topic = {}
    for i, t in enumerate(TOPIC_ORDER):
        seg = NEW[i*30:(i+1)*30]
        # 校验 left/right 各 15
        lc = sum(1 for x in seg if x[0]=="left")
        rc = sum(1 for x in seg if x[0]=="right")
        assert lc==15 and rc==15, f"{t}: left={lc} right={rc}"
        by_topic[t] = seg
    return by_topic


def main() -> int:
    write = "--write" in sys.argv
    with PUBLIC.open("r", encoding="utf-8") as f:
        data = json.load(f)
    items = data["items"]

    # 现有骨架集
    existing = set()
    for it in items:
        existing.add((it.get("side",""), skel(it.get("title_cn",""))))

    by_topic = assign_topics()
    new_items = []
    seen_new = set()
    collisions = 0
    for topic, seg in by_topic.items():
        for t in seg:
            it = build_item(t)
            it["topic"] = topic
            k = (it["side"], skel(it["title_cn"]))
            if k in existing or k in seen_new:
                collisions += 1
                print(f"[碰撞] {k} -> {it['title_cn'][:40]}")
                continue
            seen_new.add(k)
            new_items.append(it)

    print(f"\n新增条数: {len(new_items)} / 规划 {len(NEW)}")
    print(f"骨架碰撞: {collisions} (应为 0)")

    # 预览合并后统计
    merged = items + new_items
    from collections import Counter
    tc = Counter(it.get("topic") for it in merged)
    sc = Counter(it.get("side") for it in merged)
    print(f"\n=== 合并后预览（未写入）===")
    print(f"总计 {len(merged)} 条 | 方向 {dict(sc)}")
    for t in TOPIC_ORDER:
        mark = "OK" if tc[t]>=50 else "不足"
        print(f"  {t}: {tc[t]} [{mark}]")
    # 再次校验整体骨架无碰撞
    allk = set(); dup=0
    for it in merged:
        k=(it["side"], skel(it["title_cn"]))
        if k in allk: dup+=1
        allk.add(k)
    print(f"合并后整体骨架碰撞: {dup} (应为 0)")

    if collisions or dup:
        print("\n[中止] 存在碰撞，未写入。请修正 NEW 数据。")
        return 1
    if not write:
        print("\n[dry-run] 未写入。加 --write 实际写回两个 JSON 文件。")
        return 0

    data["items"] = merged
    for path in (PUBLIC, CONTENT):
        with path.open("w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
        print(f"已写入: {path}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
